import{_ as d,o as a,c as r,a7 as e}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"混沌界域（Chaos）","description":"","frontmatter":{},"headers":[],"relativePath":"realms/chaos.md","filePath":"zh/realms/chaos.md","lastUpdated":1775394001000}'),o={name:"realms/chaos.md"};function l(s,t,n,h,i,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="混沌界域-chaos" tabindex="-1">混沌界域（Chaos） <a class="header-anchor" href="#混沌界域-chaos" aria-label="Permalink to &quot;混沌界域（Chaos）&quot;">​</a></h1><p><span class="realm-badge realm-chaos">混沌 Chaos</span></p><h2 id="界域特性" tabindex="-1">界域特性 <a class="header-anchor" href="#界域特性" aria-label="Permalink to &quot;界域特性&quot;">​</a></h2><p>混沌是最灵活的界域，其核心特性是<strong>可以与任意一个其他界域混搭</strong>，同时加速银钥能量的积累。v2.4版本界域强度评级为 <strong>A+</strong>。</p><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><ul><li><strong>死亡抵抗</strong> — 任意队伍中如果存在混沌唤醒体，可以额外获得100%死亡抵抗（免死1次）</li><li><strong>银钥共鸣</strong> — 纯混沌编成时，每回合结束自动积攒250点银钥能量。每回合可使用2次钥令，同回合第2次使用钥令时，可从已解锁的其他钥令中选择一个使用</li><li><strong>界域混搭</strong> — v1.x可与任意界域角色组队；v2.0后仍保持此特性</li></ul><h3 id="混沌共生效果-v2-0" tabindex="-1">混沌共生效果 (v2.0+) <a class="header-anchor" href="#混沌共生效果-v2-0" aria-label="Permalink to &quot;混沌共生效果 (v2.0+)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>搭配界域</th><th>共生效果</th></tr></thead><tbody><tr><td><span class="realm-badge realm-aequor">深海</span> 深海共生</td><td>混沌觉醒体发动狂气爆发后，回合结束时额外1个触手攻击敌人，并给予所有深海觉醒体10点狂气</td></tr><tr><td><span class="realm-badge realm-caro">血肉</span> 血肉共生</td><td>回合结束时每有一个混沌觉醒体，蓄积2%最大生命的猩红炉；混沌觉醒体使用狂气爆发时，胚融合+25%</td></tr><tr><td><span class="realm-badge realm-ultra">超维</span> 超维共生</td><td>战斗开始时每有一个混沌觉醒体，最大生命力永久增加1%，所有敌人最大生命力降低0.5%，所有超维觉醒体暴击伤害增加10%</td></tr></tbody></table><h2 id="混沌界域唤醒体" tabindex="-1">混沌界域唤醒体 <a class="header-anchor" href="#混沌界域唤醒体" aria-label="Permalink to &quot;混沌界域唤醒体&quot;">​</a></h2><table tabindex="0"><thead><tr><th>唤醒体</th><th>定位</th><th>Tier</th><th>获取方式</th></tr></thead><tbody><tr><td>艾尔瓦 (Alva)</td><td>防御</td><td>T0</td><td>常驻/活动唤醒</td></tr><tr><td>朵尔 (Doll)</td><td>输出</td><td>T0</td><td>常驻/活动唤醒</td></tr><tr><td>环行·拉蒙娜 (Ramona: Timeworn)</td><td>输出</td><td>T0</td><td>限定活动唤醒</td></tr><tr><td>24</td><td>输出</td><td>T0</td><td>限定活动唤醒</td></tr><tr><td>奥吉尔 (Ogier)</td><td>辅助</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>萝坦 (Lotan)</td><td>防御</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>拉蒙娜 (Ramona)</td><td>辅助</td><td>T1</td><td>常驻/活动唤醒</td></tr><tr><td>莉莉 (Lily)</td><td>防御</td><td>T1</td><td>活动唤醒「花不染尘」</td></tr><tr><td>淡墨 (Danmo)</td><td>输出</td><td>T1</td><td>限定活动唤醒</td></tr><tr><td>潘狄娅 (Pandya)</td><td>副输出</td><td>T2</td><td>常驻/活动唤醒</td></tr><tr><td>诺缔拉 (Nodera)</td><td>输出</td><td>T2</td><td>常驻/活动唤醒</td></tr><tr><td>伽伦 (Galen)</td><td>副输出</td><td>T3</td><td>常驻/活动唤醒</td></tr><tr><td>宁菲亚 (Nymphia)</td><td>辅助</td><td>T3</td><td>常驻/活动唤醒</td></tr><tr><td>莱克 (Karen)</td><td>辅助</td><td>—</td><td>活动唤醒</td></tr><tr><td>哈姆林 (Hameln)</td><td>辅助</td><td>—</td><td>唤醒</td></tr><tr><td>塔薇 (Tawil)</td><td>辅助</td><td>—</td><td>唤醒</td></tr><tr><td>熔毁·朵尔 (Doll: Inferno)</td><td>辅助</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>凯蒂古拉 (Kathigu-Ra)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr><tr><td>茉夏 (Mouchette)</td><td>输出</td><td>—</td><td>限定活动唤醒</td></tr></tbody></table><h2 id="构筑建议" tabindex="-1">构筑建议 <a class="header-anchor" href="#构筑建议" aria-label="Permalink to &quot;构筑建议&quot;">​</a></h2><p>混沌界域的构筑核心在于利用死亡抵抗和银钥共鸣：</p><ol><li><strong>纯混沌</strong> — 每回合自动积攒250银钥能量，可每回合使用2次钥令。推荐阵容：24+拉蒙娜+奥吉尔+莉莉</li><li><strong>搭配深海</strong> — 深海共生提供额外触手攻击+狂气。推荐：24+图鲁+墨菲+珊</li><li><strong>搭配血肉</strong> — 血肉共生蓄积猩红炉+胚融合加速</li><li><strong>搭配超维</strong> — 超维共生提供生命力加成和暴伤增益</li></ol><div class="tip custom-block"><p class="custom-block-title">新手建议</p><p>混沌最明显的就是死亡抵抗，知道这一点之后就敢放心卖死抗。新手开荒推荐使用初始四小只（混沌SR角色）。</p></div>',14)])])}const b=d(o,[["render",l]]);export{p as __pageData,b as default};
